</div>\r\n                    </div>\r\n                </div>\r\n\r\n                <div class=\"d-flex justify-content-end mb-2\">\r\n                    <div\r\n                        class=\"btn-group mr-2\"\r\n                        role=\"group\"\r\n                        aria-label=\"First group\"\r\n                    >\r\n                        <button\r\n                            type=\"button\"\r\n                            :disabled=\"disableSend\"\r\n                            class=\"btn btn-success\"\r\n                            @click=\"sendOrden()\"\r\n                            :loading=\"loading\"\r\n                        >\r\n                            <i class=\"icofont-checked\"></i>\r\n\r\n                            Cobrar\r\n                        </button>\r\n                        <button\r\n                            type=\"button\"\r\n                            class=\"btn btn-danger\"\r\n                            id=\"close_offcanvas\"\r\n                            data-bs-dismiss=\"offcanvas\"\r\n                            aria-label=\"Close\"\r\n                        >\r\n                            <i class=\"icofont-checked\"></i\r\n                            ><i class=\"icofont-close-line\"></i> Cancelar\r\n                        </button>\r\n                    </div>\r\n                    <!-- <div class=\"btn-group check-all-container mt-n1\" v-if=\"localOrden.length>0\">\r\n                                    <div class=\"btn btn-sm btn-primary\" @click=\"sendOrden()\" :loading=\"loading\">\r\n                                            <i class=\"icofont-checked\"></i>   Enviar Pedido - Cobrar\r\n                                     </div>\r\n                                       <div class=\"btn btn-sm btn-danger\" id=\"close_offcanvas\"  data-bs-dismiss=\"offcanvas\" aria-label=\"Close\" @click=\"close()\">\r\n                                         <i class=\"icofont-close-line\"></i> Cancelar\r\n                                     </div>\r\n                                    </div> -->\r\n                </div>\r\n                <div class=\"row align-items-start\">\r\n                    <div class=\"col-md-6 text-end pt-2 pb-2 font-weight-light\">\r\n                        <label class=\"control-label w-100\">Para llevar</label>\r\n                        <el-switch\r\n                            v-model=\"to_carry\"\r\n                            active-text=\"Si\"\r\n                            inactive-text=\"No\"\r\n                        ></el-switch>\r\n                    </div>\r\n\r\n                    <div class=\"col-md-6 text-end pt-2 pb-2 font-weight-light\">\r\n                        <h3 class=\"badge text-success lead-font-weight-700\">\r\n                            Total Pedido: S/. {{ total.toFixed(2) }}\r\n                        </h3>\r\n                    </div>\r\n                </div>\r\n                <div class=\"scroll-out\">\r\n                    <div\r\n                        class=\"scroll-by-count os-host os-theme-dark os-host-overflow os-host-overflow-y os-host-resize-disabled os-host-scrollbar-horizontal-hidden os-host-transition\"\r\n                        data-count=\"4\"\r\n                        id=\"checkboxTable\"\r\n                        style=\"height: calc(100vh - 8rem);\"\r\n                    >\r\n                        <div class=\"os-resize-observer-host observed\">\r\n                            <div\r\n                                class=\"os-resize-observer\"\r\n                                style=\"left: 0px; right: auto;\"\r\n                            ></div>\r\n                        </div>\r\n                        <div\r\n                            class=\"os-size-auto-observer observed\"\r\n                            style=\"height: calc(100% + 1px); float: left;\"\r\n                        >\r\n                            <div class=\"os-resize-observer\"></div>\r\n                        </div>\r\n                        <div\r\n                            class=\"os-content-glue\"\r\n                            style=\"margin: 0px 5px;\"\r\n                        ></div>\r\n                        <div class=\"os-padding\">\r\n                            <div\r\n                                class=\"os-viewport os-viewport-native-scrollbars-invisible\"\r\n                                style=\"overflow-y: scroll;\"\r\n                            >\r\n                                <div\r\n                                    class=\"os-content\"\r\n                                    style=\"padding: 0px 5px; height: 100%; width: 100%;\"\r\n                                >\r\n                                    <div\r\n                                        class=\"col-sm-12 col-md-12 col-lg-12  col-xl-12\"\r\n                                        v-for=\"(order_pend,\r\n                                        indexx) in localOrden\"\r\n                                        :key=\"indexx\"\r\n                                    >\r\n                                        <!--  -->\r\n                                        <div\r\n                                            class=\"coupon rounded d-flex justify-content-between mb-2\"\r\n                                            id=\"card\"\r\n                                        >\r\n                                            <div\r\n                                                class=\"tengah py-2 d-flex w-100 justify-content-start  p-2\"\r\n                                            >\r\n                                                <div>\r\n                                                    <h3\r\n                                                        class=\"lead font-weight-light\"\r\n                                                    >\r\n                                                        {{\r\n                                                            order_pend.food.description.toUpperCase()\r\n                                                        }}\r\n                                                    </h3>\r\n                                                    <p\r\n                                                        class=\"badge bg-foreground text-uppercase font-weight-light p-0\"\r\n                                                    ></p>\r\n                                                    <div\r\n                                                        class=\"row align-items-end\"\r\n                                                    >\r\n                                                        <div class=\"col-md-5\">\r\n                                                            <span\r\n                                                                class=\"text-muted\"\r\n                                                            >\r\n                                                                Cantidad<br />\r\n                                                                <div\r\n                                                                    class=\"input-group spinner\"\r\n                                                                    data-trigger=\"spinner\"\r\n                                                                >\r\n                                                                    <input\r\n                                                                        type=\"text\"\r\n                                                                        readonly\r\n                                                                        class=\"form-control text-center\"\r\n                                                                        v-model=\"\r\n                                                                            order_pend.quantity\r\n                                                                        \"\r\n                                                                        data-rule=\"currency\"\r\n                                                                    />\r\n                                                                    <div\r\n                                                                        class=\"input-group-text\"\r\n                                                                    >\r\n                                                                        <button\r\n                                                                            type=\"button\"\r\n                                                                            class=\"spin-up\"\r\n                                                                            data-spin=\"up\"\r\n                                                                            @click=\"\r\n                                                                                sumar_orden(\r\n                                                                                    indexx\r\n                                                                                )\r\n                                                                            \"\r\n                                                                        >\r\n                                                                            <span\r\n                                                                                class=\"arrow\"\r\n                                                                            ></span>\r\n                                                                        </button>\r\n                                                                        <button\r\n                                                                            type=\"button\"\r\n                                                                            class=\"spin-down\"\r\n                                                                            data-spin=\"down\"\r\n                                                                            @click=\"\r\n                                                                                restar_orden(\r\n                                                                                    indexx\r\n                                                                                )\r\n                                                                            \"\r\n                                                                        >\r\n                                                                            <span\r\n                                                                                class=\"arrow\"\r\n                                                                            ></span>\r\n                                                                        </button>\r\n                                                                    </div>\r\n                                                                </div>\r\n                                                            </span>\r\n                                                        </div>\r\n\r\n                                                        <div class=\"col-md-5\">\r\n                                                            <span\r\n                                                                class=\"time font-weight-light\"\r\n                                                            >\r\n                                                                <span\r\n                                                                    class=\"text-muted\"\r\n                                                                >\r\n                                                                    Precio\r\n                                                                    <br />\r\n                                                                    <el-input\r\n                                                                        type=\"number\"\r\n                                                                        v-model=\"\r\n                                                                            order_pend.price\r\n                                                                        \"\r\n                                                                        @input=\"\r\n                                                                            update_price(\r\n                                                                                indexx,\r\n                                                                                order_pend.price\r\n                                                                            )\r\n                                                                        \"\r\n                                                                    >\r\n                                                                        <template\r\n                                                                            slot=\"prepend\"\r\n                                                                            v-if=\"\r\n                                                                                order_pend\r\n                                                                                    .food\r\n                                                                                    .item\r\n                                                                                    .currency_type_id ==\r\n                                                                                    'PEN'\r\n                                                                            \"\r\n                                                                        >\r\n                                                                            S/\r\n                                                                        </template>\r\n                                                                        <template\r\n                                                                            slot=\"prepend\"\r\n                                                                            v-if=\"\r\n                                                                                order_pend\r\n                                                                                    .food\r\n                                                                                    .item\r\n                                                                                    .currency_type_id ==\r\n                                                                                    'USD'\r\n                                                                            \"\r\n                                                                        >\r\n                                                                            $\r\n                                                                        </template>\r\n                                                                    </el-input>\r\n                                                                </span>\r\n                                                            </span>\r\n                                                        </div>\r\n                                                        <div\r\n                                                            class=\"col-md-2 p-0\"\r\n                                                        >\r\n                                                            <span\r\n                                                                class=\"time font-weight-light\"\r\n                                                            >\r\n                                                                <span\r\n                                                                    class=\"text-muted\"\r\n                                                                >\r\n                                                                    <el-button\r\n                                                                        class=\"text-white\"\r\n                                                                        type=\"danger\"\r\n                                                                        icon=\"el-icon-delete\"\r\n                                                                        @click=\"\r\n                                                                            deleteFood(\r\n                                                                                indexx\r\n                                                                            )\r\n                                                                        \"\r\n                                                                    >\r\n                                                                    </el-button>\r\n                                                                </span>\r\n                                                            </span>\r\n                                                            <!-- <el-button-group>\r\n                                                        <el-button class=\"text-white\" type=\"danger\" icon=\"el-icon-delete\" @click=\"deleteFood(indexx)\">\r\n                                                        </el-button>\r\n                                                        <el-button class=\"text-white\" type=\"info\" icon=\"el-icon-s-order\"  @click=\"openLocalObservationDialog(indexx)\">\r\n                                                        </el-button>\r\n                                                    </el-button-group> -->\r\n                                                        </div>\r\n                                                    </div>\r\n                                                </div>\r\n                                            </div>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n            </section>\r\n        </div>\r\n    </div>\r\n</template>\r\n<script>\r\nimport splitPayment from \"./split_payment.vue\";\r\nexport default {\r\n    props: [\"localOrden\", \"configuration\", \"ordens\"],\r\n    created() {},\r\n\r\n    data() {\r\n        return {\r\n            pin: \"\",\r\n            totalOrdenItems: 0.0,\r\n            total: 0.0,\r\n            disableSend: false,\r\n            totalOrden: 0.0,\r\n            loading: false,\r\n            commands_fisico: \"\",\r\n            AllSelected: false,\r\n            showDialogPing: false,\r\n            dialogLocalObservation: false,\r\n            currentLocalOrden: null,\r\n            localObservation: null,\r\n            dialogObservation: false,\r\n            observation: null,\r\n            loadingObservation: false,\r\n            currentOrden: null,\r\n            form_ped: {},\r\n            to_carry: false\r\n        };\r\n    },\r\n    watch: {\r\n        ordens(newOrdens, _) {\r\n            this.calculateTotal(newOrdens);\r\n        }\r\n    },\r\n    mounted() {},\r\n    async created() {\r\n        qz.security.setCertificatePromise((resolve, reject) => {\r\n            this.$http\r\n                .get(\"/api/qz/crt/override\", {\r\n                    responseType: \"text\"\r\n                })\r\n                .then(response => {\r\n                    resolve(response.data);\r\n                })\r\n                .catch(error => {\r\n                    reject(error.data);\r\n                });\r\n        });\r\n        qz.security.setSignaturePromise(toSign => {\r\n            return (resolve, reject) => {\r\n                this.$http\r\n                    .post(\"/api/qz/signing\", {\r\n                        request: toSign\r\n                    })\r\n                    .then(response => {\r\n                        resolve(response.data);\r\n                    })\r\n                    .catch(error => {\r\n                        reject(error.data);\r\n                    });\r\n            };\r\n        });\r\n    },\r\n    methods: {\r\n        addNumberPin(number) {\r\n            if (this.pin.length >= 4) {\r\n                return;\r\n            }\r\n            this.pin += number.toString();\r\n        },\r\n        close() {\r\n            this.$emit(\"update:localOrden\", []);\r\n        },\r\n        update_price(index, sale_unit_price) {\r\n            let localOrden_update = this.localOrden;\r\n            localOrden_update[index].food.sale_unit_price = sale_unit_price;\r\n            this.$emit(\"update:localOrden\", localOrden_update);\r\n            this.calculateTotal();\r\n        },\r\n        sumar_orden(index) {\r\n            let localOrden_quantity = this.localOrden;\r\n            localOrden_quantity[index].quantity =\r\n                localOrden_quantity[index].quantity + 1;\r\n            this.$emit(\"update:localOrden\", localOrden_quantity);\r\n            this.calculateTotal();\r\n        },\r\n        restar_orden(index) {\r\n            let localOrden_quantity = this.localOrden;\r\n            if (localOrden_quantity[index].quantity > 1) {\r\n                localOrden_quantity[index].quantity =\r\n                    localOrden_quantity[index].quantity - 1;\r\n                this.$emit(\"update:localOrden\", localOrden_quantity);\r\n            }\r\n            this.calculateTotal();\r\n        },\r\n        async printTicket() {\r\n            let id = this.ordens[0].orden_id;\r\n            //  let total = this.totalOrdenItems;\r\n            //   try {\r\n            //     printjs({\r\n            //       printable: `restaurant/worker/print-ticket?id=${id}&total=${total}`,\r\n            //       type: \"pdf\",\r\n            //       showModal: true,\r\n            //       modalMessage: \"Espere por favor...\",\r\n            //     });\r\n            //   } catch (e) {\r\n            //     console.log(e.response);\r\n            //   }\r\n            try {\r\n                const response = await this.$http.get(\r\n                    `/restaurant/worker/record/${id}`\r\n                );\r\n                let config = qz.configs.create(response.data.printer, {\r\n                    scaleContent: false\r\n                });\r\n                if (!qz.websocket.isActive()) {\r\n                    await qz.websocket.connect(config);\r\n                }\r\n                let data = [\r\n                    {\r\n                        type: \"pdf\",\r\n                        format: \"file\",\r\n                        data: response.data.print\r\n                    }\r\n                ];\r\n                qz.print(config, data).catch(e => {\r\n                    this.$toast.error(e.message);\r\n                });\r\n\r\n                //this.$toast.success(\"se esta imprimiendo el comprobante con exito\");\r\n                // qz.websocket.disconnect()\r\n            } catch (e) {\r\n                this.$toast.error(e.message);\r\n            }\r\n        },\r\n\r\n        view_orders() {\r\n            $(\".style-switcher\")\r\n                .animate(\r\n                    {\r\n                        right: \"0\"\r\n                    },\r\n                    300\r\n                )\r\n                .addClass(\"active\");\r\n        },\r\n        selectAllCats() {},\r\n        closeDialog(ordenId = null) {\r\n            let ordenToAdd = [...this.localOrden];\r\n            ordenToAdd = ordenToAdd.map(o => ({\r\n                status_orden_id: 1,\r\n                food: {\r\n                    description: o.food.description,\r\n                    price: o.food.price\r\n                },\r\n                observations: o.observation\r\n            }));\r\n            // let allOrdens = [...ordenToAdd, ...this.ordens];\r\n            this.$emit(\"updateOrdens\", ordenId);\r\n            this.$emit(\"listtables\");\r\n            // this.$emit(\"update:ordens\", allOrdens);\r\n            this.$emit(\"update:localOrden\", []);\r\n            this.$eventHub.$emit(\"reloadData\");\r\n            this.totalOrdenItems = 0.0;\r\n            this.total = 0.0;\r\n            this.totalOrden = 0.0;\r\n        },\r\n        clear_command() {\r\n            this.commands_fisico = null;\r\n        },\r\n        async sendOrden() {\r\n            if (this.configuration.commands_fisico == true) {\r\n                if (\r\n                    this.commands_fisico == \"\" ||\r\n                    this.commands_fisico == null ||\r\n                    this.commands_fisico.length == 0\r\n                ) {\r\n                    return this.$toast.error(\r\n                        \"Debe ingresar la comanda fisica\"\r\n                    );\r\n                }\r\n            }\r\n            this.disableSend = true;\r\n            let form_submit = {\r\n                id: null,\r\n                caja: true,\r\n                printing: this.configuration.print_commands,\r\n                commands_fisico: this.commands_fisico,\r\n                print_kitchen: this.configuration.print_kitchen,\r\n                to_carry: this.to_carry,\r\n                orden: {\r\n                    table_id: 1,\r\n                    status_orden_id: 1\r\n                },\r\n                items: this.localOrden,\r\n                pin: null\r\n            };\r\n            this.loading = true;\r\n            // const responses = await this.$http.post(\r\n            //     \"/restaurant/worker/send-orden\",\r\n            //     form_submit\r\n            // );\r\n\r\n            this.commands_fisico = \"\";\r\n            this.to_carry = false;\r\n            //    let IdOrdensend = responses.data.id;\r\n            //    if (responses.data.success == true) {\r\n\r\n            this.loading = false;\r\n            // this.$toast.success(responses.data.message);\r\n            this.disableSend = false;\r\n            document.querySelector(\"#close_offcanvas\").click();\r\n            // } else {\r\n            //     this.loading = false;\r\n            //     this.$toast.error(responses.data.message);\r\n            // }\r\n\r\n            this.loading = false;\r\n            this.disableSend = false;\r\n            this.$emit(\"paymentsOrden\", form_submit);\r\n        },\r\n        formatUrlImage(url) {\r\n            if (!url) return;\r\n            let formated = \"storage/uploads/items/\" + url;\r\n            return `/${formated}`;\r\n        },\r\n        async cancelGeneralOrden() {\r\n            this.loading = true;\r\n            try {\r\n                let res = await this.$confirm(\r\n                    \"Desea cancelar toda la orden?\",\r\n                    \"Cancelar\",\r\n                    {\r\n                        confirmButtonText: \"Ok\",\r\n                        cancelButtonText: \"Cancelar\",\r\n                        type: \"warning\"\r\n                    }\r\n                );\r\n                if (res) {\r\n                    let form = {\r\n                        id: this.ordens[0].orden_id\r\n                    };\r\n                    const response = await this.$http.post(\r\n                        \"cancel-orden\",\r\n                        form\r\n                    );\r\n                    if (response.status == 200) {\r\n                        const { message } = response.data;\r\n                        this.$toast.success(message);\r\n                        this.$eventHub.$emit(\"reloadData\");\r\n                        this.$emit(\"ordenDeleted\");\r\n                    }\r\n                }\r\n            } catch (e) {\r\n                if (e != \"cancel\") {\r\n                    console.log(e);\r\n                    this.$toast.error(\"Ocurrió un error\");\r\n                }\r\n            }\r\n            this.loading = false;\r\n        },\r\n        calculateTotal(w = null) {\r\n            this.totalOrdenItems = 0.0;\r\n            this.total = 0.0;\r\n            this.totalOrden = 0.0;\r\n            let OrdenPen = 0;\r\n            let OrdenPenAtendidos = 0;\r\n            let nTotal_poratendidos = _.forEach(this.localOrden, function(\r\n                value\r\n            ) {\r\n                OrdenPen = parseFloat(OrdenPen) + value.quantity * value.price;\r\n            });\r\n            this.totalOrden = _.round(OrdenPen, 2);\r\n            let nTotal_atendidos = _.forEach(this.ordens, function(values) {\r\n                OrdenPenAtendidos =\r\n                    parseFloat(OrdenPenAtendidos) +\r\n                    values.quantity * values.price;\r\n            });\r\n            this.totalOrdenItems = _.round(OrdenPenAtendidos, 2);\r\n            this.total = this.totalOrden + this.totalOrdenItems;\r\n            this.$emit(\"total_sales\", this.total);\r\n        },\r\n        deleteFood(idx) {\r\n            this.$emit(\"deletedFood\", idx);\r\n            this.calculateTotal();\r\n        },\r\n        async submit() {\r\n            //this.loading = true;\r\n            this.showDialogPing = true;\r\n            this.open_orders();\r\n        },\r\n        async cancelOrden(id) {\r\n            try {\r\n                let res = await this.$confirm(\r\n                    \"Desea cancelar este pedido?\",\r\n                    \"Cancelar\",\r\n                    {\r\n                        confirmButtonText: \"Ok\",\r\n                        cancelButtonText: \"Cancelar\",\r\n                        type: \"warning\"\r\n                    }\r\n                );\r\n                if (res) {\r\n                    const response = await this.$http.delete(\r\n                        `delete-orden/${id}`\r\n                    );\r\n                    if (response.status == 200) {\r\n                        const { message } = response.data;\r\n                        let newOrdenItems = [...this.ordens];\r\n                        newOrdenItems = newOrdenItems.filter(n => n.id != id);\r\n                        this.$emit(\"update:ordens\", newOrdenItems);\r\n                        this.$eventHub.$emit(\"reloadData\");\r\n                        this.$toast.success(message);\r\n                    }\r\n                }\r\n            } catch (e) {\r\n                //todo\r\n                if (e != \"cancel\") {\r\n                    this.$toast.error(\"Ocurrió un error\");\r\n                }\r\n            }\r\n        },\r\n        async ordenReady(id) {\r\n            this.loading = true;\r\n            try {\r\n                const response = await this.$http.get(`ordens-ready/${id}`);\r\n\r\n                const { success, message } = response.data;\r\n                success\r\n                    ? this.$toast.success(message)\r\n                    : this.$toast.error(message);\r\n                if (success) {\r\n                    let cloneOrdenItems = [...this.ordens];\r\n                    cloneOrdenItems = cloneOrdenItems.map(o => {\r\n                        if (o.id == id) {\r\n                            o.status_orden_id = 3;\r\n                        }\r\n                        return o;\r\n                    });\r\n                    this.$emit(\"update:ordens\", cloneOrdenItems);\r\n                }\r\n            } catch (e) {\r\n                console.log(e);\r\n                this.$toast.error(\"Ocurrió un error\");\r\n            }\r\n            this.loading = false;\r\n        },\r\n        async changeObservation() {\r\n            //this.localObservation\r\n            this.loadingObservation = true;\r\n            const response = await this.$http.post(\"change-observation\", {\r\n                observation: this.observation,\r\n                id: this.currentOrden\r\n            });\r\n            if (response.status == 200) {\r\n                this.$eventHub.$emit(\"reloadData\");\r\n                let newOrdenItems = [...this.ordens];\r\n                newOrdenItems.find(\r\n                    n => n.id == this.currentOrden\r\n                ).observations = this.observation;\r\n            }\r\n            this.loadingObservation = false;\r\n            this.closeObservationDialog();\r\n        },\r\n        openObservationDialog(id, idx) {\r\n            this.currentOrden = id;\r\n            this.observation = this.ordens[idx].observations;\r\n            this.dialogObservation = true;\r\n        },\r\n        closeObservationDialog() {\r\n            this.dialogObservation = false;\r\n            this.observation = null;\r\n        },\r\n        changeLocalObservation() {\r\n            let ordenModified = [...this.localOrden];\r\n            ordenModified[\r\n                this.currentLocalOrden\r\n            ].observation = this.localObservation;\r\n            this.$emit(\"update:localOrden\", ordenModified);\r\n            this.closeLocalObservationDialog();\r\n        },\r\n        openLocalObservationDialog(idx) {\r\n            this.currentLocalOrden = idx;\r\n            this.localObservation = this.localOrden[idx].observation;\r\n            this.dialogLocalObservation = true;\r\n        },\r\n        closeLocalObservationDialog() {\r\n            this.dialogLocalObservation = false;\r\n            this.currentLocalOrden = null;\r\n            this.localObservation = null;\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/pos/partials/drawer.vue","<template>\r\n    <el-dialog\r\n        append-to-body\r\n        @open=\"open\"\r\n        @close=\"close\"\r\n        :visible=\"showSplitPayment\"\r\n        :title=\"`Dividir pago: S/. ${total}`\"\r\n        width=\"70%\"\r\n    >\r\n        <div class=\"d-flex flex-column p-2\">\r\n            <div class=\"d-flex flex-row align-items-end\">\r\n                <div>\r\n                    <label for=\"\">Dividir entre:</label><br />\r\n                    <el-input-number\r\n                        v-if=\"splitByAmount == '1'\"\r\n                        :max=\"10\"\r\n                        @input=\"updatePayments\"\r\n                        v-model=\"number\"\r\n                    ></el-input-number>\r\n                    <el-input-number\r\n                        v-else\r\n                        :max=\"items.length\"\r\n                        @input=\"updatePayments\"\r\n                        v-model=\"numberProduct\"\r\n                    ></el-input-number>\r\n                </div>\r\n                <div style=\"margin-left:10px;\">\r\n                    <el-radio-group\r\n                        v-model=\"splitByAmount\"\r\n                        @change=\"updatePayments\"\r\n                    >\r\n                        <el-radio-button label=\"1\">Por cuotas</el-radio-button>\r\n                        <el-radio-button label=\"2\"\r\n                            >Por producto</el-radio-button\r\n                        >\r\n                    </el-radio-group>\r\n                </div>\r\n            </div>\r\n\r\n            <div v-if=\"splitByAmount == '1'\" class=\"d-flex flex-wrap \">\r\n                <div\r\n                    class=\"col-3\"\r\n                    v-for=\"(payment, idx) in payments\"\r\n                    :key=\"idx\"\r\n                >\r\n                    <!--    <div class=\"form-check m-2\">\r\n                  <input\r\n                            class=\"form-check-input\"\r\n                            type=\"checkbox\"\r\n                            v-model=\"payment.fixed\"\r\n                            :id=\"idx\"\r\n                        />\r\n                        <label class=\"form-check-label\" :for=\"idx\">\r\n                            Fijar\r\n                        </label> \r\n                    </div>-->\r\n                    <div style=\"margin-top:10px; margin-right:5px;\">\r\n                        <h2 class=\"text-muted text-small\">\r\n                            Cuota {{ idx + 1 }}\r\n                        </h2>\r\n                        <!-- <el-input-number\r\n                            :disabled=\"payment.fixed\"\r\n                            :precision=\"2\"\r\n                            :step=\"0.1\"\r\n                            v-model=\"payment.amount\"\r\n                        ></el-input-number> -->\r\n                        <el-input v-model=\"payment.amount\" readonly></el-input>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div v-else>\r\n                <div class=\"d-flex flex-wrap\">\r\n                    <div class=\"col-2\" v-for=\"(item, idx) in items\" :key=\"idx\">\r\n                        <div\r\n                            role=\"button\"\r\n                            @click=\"addItem(item)\"\r\n                            class=\"card p-1\"\r\n                            style=\" margin-top:10px; margin-right:5px;\"\r\n                        >\r\n                            <h2 class=\"text-muted text-small\">\r\n                                {{ item.food.description }}\r\n                            </h2>\r\n\r\n                            <h3 class=\"text-muted text-small\">\r\n                                S/. {{ item.price }}\r\n                            </h3>\r\n                            <h3\r\n                                :class=\"\r\n                                    ` text-small ${\r\n                                        item.quantity == 0\r\n                                            ? 'text-danger'\r\n                                            : 'text-muted'\r\n                                    }`\r\n                                \"\r\n                            >\r\n                                Cantidad: {{ item.quantity }}\r\n                            </h3>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div\r\n                    style=\"margin-top:15px;\"\r\n                    class=\"d-flex flex-wrap justify-content-center\"\r\n                >\r\n                    <div\r\n                        class=\"col-3 \"\r\n                        v-for=\"(payment, idx) in payments\"\r\n                        :key=\"idx\"\r\n                        style=\"margin:5px;\"\r\n                    >\r\n                        <table class=\"col-12\">\r\n                            <thead>\r\n                                <tr\r\n                                    role=\"button\"\r\n                                    @click=\"selectAccount(idx)\"\r\n                                    :class=\"\r\n                                        `${\r\n                                            payment.selected\r\n                                                ? 'bg-primary text-white border rounded-top'\r\n                                                : 'border rounded-top'\r\n                                        }`\r\n                                    \"\r\n                                >\r\n                                    <th class=\"text-center\" colspan=\"3\">\r\n                                        <b> CUENTA {{ idx + 1 }} </b>\r\n                                    </th>\r\n                                </tr>\r\n                            </thead>\r\n                            <tbody\r\n                                class=\"border rounded-top \"\r\n                                v-if=\"\r\n                                    payment.products &&\r\n                                        payment.products.length > 0\r\n                                \"\r\n                            >\r\n                                <tr\r\n                                    v-for=\"(product, idx) in payment.products\"\r\n                                    :key=\"idx\"\r\n                                >\r\n                                    <td>\r\n                                        <h3 class=\"text-muted text-small\">\r\n                                            {{ product.quantity }}\r\n                                        </h3>\r\n                                    </td>\r\n                                    <td>\r\n                                        <h3 class=\"text-muted text-small\">\r\n                                            {{ product.description }}\r\n                                        </h3>\r\n                                    </td>\r\n                                    <td style=\"text-align:right\">\r\n                                        <h3 class=\"text-muted text-small\">\r\n                                            {{\r\n                                                product.price * product.quantity\r\n                                            }}\r\n\r\n                                            <b\r\n                                                class=\"text-danger\"\r\n                                                role=\"button\"\r\n                                                @click=\"removeItem(product.id)\"\r\n                                            >\r\n                                                x\r\n                                            </b>\r\n                                        </h3>\r\n                                    </td>\r\n                                </tr>\r\n                                <tr>\r\n                                    <td\r\n                                        colspan=\"2\"\r\n                                        class=\"text-muted text-small\"\r\n                                        style=\"text-align:right\"\r\n                                    >\r\n                                        <b>\r\n                                            Total\r\n                                        </b>\r\n                                    </td>\r\n                                    <td class=\"text-muted text-small\">\r\n                                        S/.\r\n                                        {{\r\n                                            totalItemSelected(payment.products)\r\n                                        }}\r\n                                    </td>\r\n                                </tr>\r\n                            </tbody>\r\n                            <tbody v-else class=\"border\">\r\n                                <tr>\r\n                                    <td colspan=\"3\" class=\"text-center\">\r\n                                        <h3 class=\"text-muted text-small\">\r\n                                            Sin productos seleccionados\r\n                                        </h3>\r\n                                    </td>\r\n                                </tr>\r\n                            </tbody>\r\n                        </table>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n\r\n            <div class=\"row d-flex m-2 justify-content-end\">\r\n                <div class=\"col-3 d-flex justify-content-end\">\r\n                    <el-button type=\"primary\" @click=\"sendPayments\"\r\n                        >Listo</el-button\r\n                    >\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    props: [\"showSplitPayment\", \"total\", \"orden_items\"],\r\n    data() {\r\n        return {\r\n            selectedAccount: undefined,\r\n            splitByAmount: \"1\",\r\n            number: 2,\r\n            numberProduct: 2,\r\n            payments: [],\r\n            items: []\r\n        };\r\n    },\r\n    created() {\r\n        let payment = _.round(this.total / 2, 1);\r\n\r\n        this.payments = [\r\n            {\r\n                fixed: false,\r\n                amount: payment\r\n            },\r\n            {\r\n                fixed: false,\r\n                amount: payment\r\n            }\r\n        ];\r\n\r\n        if (this.total != payment * 2) {\r\n            this.payments[0].amount += _.round(payment * 2 - this.total, 1);\r\n        }\r\n    },\r\n\r\n    methods: {\r\n        totalItemSelected(products) {\r\n            let total = 0;\r\n            products.forEach(p => {\r\n                total += p.quantity * p.price;\r\n            });\r\n\r\n            return _.round(total, 2);\r\n        },\r\n        removeItem(id) {\r\n            let idx = this.payments.findIndex(p => p.selected);\r\n            if (idx > -1) {\r\n                let indexItem = this.payments[idx].products.findIndex(\r\n                    p => p.id == id\r\n                );\r\n\r\n                if (indexItem > -1) {\r\n                    let quantity = this.payments[idx].products[indexItem]\r\n                        .quantity;\r\n                    if (quantity == 1) {\r\n                        this.payments[idx].products = [\r\n                            ...this.payments[idx].products.filter(\r\n                                p => p.id != id\r\n                            )\r\n                        ];\r\n                    } else {\r\n                        this.payments[idx].products[indexItem].quantity -= 1;\r\n                    }\r\n                    let item = this.items.find(i => i.id == id);\r\n                    ++item.quantity;\r\n                    if (item.quantity == 1) {\r\n                        this.items = [\r\n                            item,\r\n                            ...this.items.filter(i => i.id != item.id)\r\n                        ];\r\n                    }\r\n                }\r\n            }\r\n        },\r\n        addItem(item) {\r\n            //checar la lista\r\n            //a que cuenta le estas agregando\r\n            if (item.quantity == 0) {\r\n                this.$toast.warning(\"No quedan unidades disponibles para dividir el producto\");\r\n                return;\r\n            }\r\n            let idx = this.payments.findIndex(p => p.selected);\r\n            if (idx > -1) {\r\n                let indexItem = this.payments[idx].products.findIndex(\r\n                    p => p.id == item.id\r\n                );\r\n\r\n                if (indexItem > -1) {\r\n                    this.payments[idx].products[indexItem].quantity += 1;\r\n                } else {\r\n                    this.payments[idx].products.push({\r\n                        price: item.price,\r\n                        description: item.food.description,\r\n                        id: item.id,\r\n                        quantity: 1\r\n                    });\r\n                }\r\n\r\n                --item.quantity;\r\n                if (item.quantity == 0) {\r\n                    this.items = [\r\n                        ...this.items.filter(i => i.id != item.id),\r\n                        item\r\n                    ];\r\n                }\r\n            } else {\r\n                this.$toast.warning(\"Seleccione una cuenta\");\r\n            }\r\n        },\r\n        async sendPayments() {\r\n            if (this.splitByAmount == \"1\") {\r\n                this.$emit(\"receivePayments\", this.payments);\r\n            } else {\r\n                if (this.items.some(i => i.quantity > 0)) {\r\n                    this.$toast.error(\"Aún hay productos por dividir\");\r\n                    return;\r\n                }\r\n                this.$emit(\"receiveProducts\", this.payments);\r\n            }\r\n            this.close();\r\n        },\r\n        changePayment(idx) {\r\n            let fixed = this.payments.filter(p => p.fixed);\r\n            let numberFixed = fixed.length;\r\n            if (fixed.length > 0) {\r\n                //obtengo el monto de los pagos fijos\r\n                fixed = fixed.reduce((a, b) => ({\r\n                    amount: a.amount + b.amount,\r\n                    fixed: true\r\n                }));\r\n                if (isNaN(fixed.amount) && fixed.amount > 0) {\r\n                    //el monto que resta del total con los pagos fijos\r\n                    let rest = this.total - fixed.amount;\r\n                    let inputSelected = this.payments[idx];\r\n                    //encontrar el input modificado y dejar el precio\r\n                    rest = rest - inputSelected.amount;\r\n                    //\r\n                }\r\n            }\r\n        },\r\n        paymentByAmount() {\r\n            let payment = _.round(this.total / this.number, 1);\r\n            this.payments = Array.from({ length: this.number }, (_, i) => ({\r\n                fixed: false,\r\n                amount: payment\r\n            }));\r\n            payment;\r\n            if (this.total != payment * this.number) {\r\n                this.payments[0].amount += _.round(\r\n                    this.total - payment * this.number,\r\n                    1\r\n                );\r\n            }\r\n            this.payments.map(p => ({\r\n                ...p,\r\n                amount: _.round(p.amount, 2)\r\n            }));\r\n        },\r\n        updatePayments() {\r\n            if (this.number < 2 || isNaN(this.number)) {\r\n                this.number = 2;\r\n            }\r\n\r\n            if (this.splitByAmount == \"1\") {\r\n                this.paymentByAmount();\r\n            } else {\r\n                this.paymentByProducts();\r\n            }\r\n        },\r\n\r\n        selectAccount(idx) {\r\n            if (\r\n                this.selectedAccount != undefined ||\r\n                this.selectedAccount != null\r\n            ) {\r\n                this.payments[this.selectedAccount].selected = false;\r\n            }\r\n            this.payments[idx].selected = true;\r\n            this.selectedAccount = idx;\r\n        },\r\n        paymentByProducts() {\r\n            this.payments = [];\r\n            this.restoreItems();\r\n            let hasProducts = this.payments.some(p => p.products);\r\n            let toAdd = this.numberProduct;\r\n            if (hasProducts) {\r\n                toAdd = this.numberProduct - this.payments.length;\r\n            }\r\n\r\n            this.payments = [\r\n                ...this.payments,\r\n                ...Array.from({ length: toAdd }, (_, i) => ({\r\n                    fixed: false,\r\n                    amount: 0,\r\n                    products: [],\r\n                    selected: false\r\n                }))\r\n            ];\r\n        },\r\n        restoreItems() {\r\n            this.items = JSON.parse(JSON.stringify(this.orden_items.items));\r\n        },\r\n        open() {\r\n            this.payments = [];\r\n            this.restoreItems();\r\n            //   this.number = 2;\r\n            //  {\r\n            //         fixed: false,\r\n            //         amount: _.round(this.total / 2, 2)\r\n            //     },\r\n            //     {\r\n            //         fixed: false,\r\n            //         amount: _.round(this.total / 2, 2)\r\n            //     }\r\n        },\r\n        close() {\r\n            this.items = [];\r\n            this.$emit(\"update:showSplitPayment\", false);\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/pos/partials/split_payment.vue","var render = function() {\n  var _vm = this\n  var _h = _vm.$createElement\n  var _c = _vm._self._c || _h\n  return _c(\n    \"el-dialog\",\n    {\n      attrs: {\n        \"append-to-body\": \"\",\n        visible: _vm.showSplitPayment,\n        title: \"Dividir pago: S/. \" + _vm.total,\n        width: \"70%\"\n      },\n      on: { open: _vm.open, close: _vm.close }\n 